# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from prometheus_client import Counter, generate_latest, REGISTRY
from flask import Flask, request, Response
import time

app = Flask(__name__)

# Dictionary to store individual counters for each user-path combination
user_path_counters = {}

def get_or_create_counter(user_id, session_id, path):
    """Get existing counter or create new one for user-path combination"""
    key = f"{user_id}_{path}"
    
    if key not in user_path_counters:
        # Create a new counter for this specific user-path combination
        safe_user_id = user_id.replace('-', '_').replace('.', '_')
        safe_path = path.replace('/', '_').replace('-', '_').replace('.', '_')
        metric_name = f'http_requests_user_{safe_user_id}_path{safe_path}_total'
        
        counter = Counter(
            metric_name,
            f'HTTP requests for user {user_id} on path {path}',
            ['user_id', 'session_id', 'path', 'method', 'status']
        )
        user_path_counters[key] = counter
    
    return user_path_counters[key]

@app.before_request
def before_request():
    request.start_time = time.time()

@app.after_request
def after_request(response):
    # Extract user_id and session_id from headers or query params
    user_id = request.headers.get('X-User-Id') or request.args.get('user_id', 'anonymous')
    session_id = request.headers.get('X-Session-Id') or request.args.get('session_id', 'unknown')
    path = request.path
    method = request.method
    status = response.status_code
    
    # Get or create counter for this user-path combination
    counter = get_or_create_counter(user_id, session_id, path)
    
    # Increment the counter with labels
    counter.labels(
        user_id=user_id,
        session_id=session_id,
        path=path,
        method=method,
        status=status
    ).inc()
    
    return response

@app.route('/metrics')
def metrics():
    return Response(generate_latest(REGISTRY), mimetype='text/plain')

@app.route('/')
def home():
    return {'message': 'Hello World'}

@app.route('/api/users')
def users():
    return {'users': ['user1', 'user2', 'user3']}

@app.route('/api/products')
def products():
    return {'products': ['product1', 'product2']}

@app.route('/api/orders')
def orders():
    return {'orders': ['order1', 'order2']}

@app.route('/api/user/<user_id>')
def user_detail(user_id):
    return {'user_id': user_id, 'name': f'User {user_id}'}

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)